# MenuTitle: IDS 汉字拼字
# -*- coding: utf-8 -*-
"""
IDS 汉字拼字脚本 (IDS Composer)

通过 Ideographic Description Sequences (IDS) 检索并创建当前字体中
已有部件能够拼成的新字符。

工作流程：
1. 列出当前字体中所有已有字符型（glyph）
2. 加载 IDS 数据库，将每个汉字拆解为部件
3. 反向检索：已有部件能拼成哪些新字
4. 将可拼成的新字符型添加到字体中

用法：在 Glyphs.app 的 Script 菜单中运行此脚本。
      脚本已内嵌所有需要的 IDS 数据和目标字表，无需额外依赖文件。
"""

from __future__ import print_function, unicode_literals
import os

# ============================================================
# 配置
# ============================================================


# IDS 操作符及其元数（operand count）
# 二元: ⿰⿱⿴⿵⿶⿷⿸⿹⿺⿻
# 三元: ⿲⿳
IDS_OPERATORS = {
    '\u2FF0': 2,  # ⿰ 左右
    '\u2FF1': 2,  # ⿱ 上下
    '\u2FF2': 3,  # ⿲ 左中右
    '\u2FF3': 3,  # ⿳ 上中下
    '\u2FF4': 2,  # ⿴ 全包围
    '\u2FF5': 2,  # ⿵ 上三包围
    '\u2FF6': 2,  # ⿶ 下三包围
    '\u2FF7': 2,  # ⿷ 左三包围
    '\u2FF8': 2,  # ⿸ 左上包围
    '\u2FF9': 2,  # ⿹ 右上包围
    '\u2FFA': 2,  # ⿺ 左下包围
    '\u2FFB': 2,  # ⿻ 重叠
}


# ============================================================
# IDS 解析器
# ============================================================


def extract_leaf_components_recursive(ids_string):
    """
    更精确地递归解析 IDS 字符串。
    使用栈来正确处理嵌套的 IDS 结构。
    
    返回:
        set of str: 叶子部件集合（每个是一个 Unicode 字符）
        如果 IDS 不可用则返回 None
    """
    if not ids_string:
        return None
    # 跳过含有非标准引用 {xxx} 的 IDS
    if '{' in ids_string or '}' in ids_string:
        return None
    if '〓' in ids_string:
        return None
    if '？' in ids_string or '?' in ids_string:
        return None
    
    leaves = set()
    for ch in ids_string:
        cp = ord(ch)
        # 跳过 IDS 操作符
        if 0x2FF0 <= cp <= 0x2FFB:
            continue
        # 跳过某些控制和格式字符
        if cp < 0x20:
            continue
        leaves.add(ch)
    
    return leaves if leaves else None


import zlib, base64

def get_embedded_data(name):
    data = base64.b64decode(EMBEDDED_DATA[name])
    return zlib.decompress(data).decode('utf-8')

def load_ids_database():
    char_to_ids = {}
    char_to_components = {}
    
    for line in get_embedded_data("ids").splitlines():
            line = line.strip('\r\n')
            if not line or line.startswith('#'):
                continue
            
            parts = line.split('\t')
            if len(parts) < 3:
                continue
            
            unicode_str = parts[0]  # e.g. "U+4E00"
            char = parts[1].strip()  # 字符本身
            
            if not char or len(char) != 1:
                continue
            
            # 尝试每个备选 IDS 描述（可能有多个，取第一个可用的）
            best_ids = None
            best_components = None
            
            for ids_col in parts[2:]:
                ids_str = ids_col.strip()
                if not ids_str:
                    continue
                
                # 如果 IDS 就是字符本身，说明是基础部件
                if ids_str == char:
                    best_ids = char
                    best_components = {char}
                    break
                
                # 尝试解析
                components = extract_leaf_components_recursive(ids_str)
                if components is not None:
                    best_ids = ids_str
                    best_components = components
                    break
            
            if best_ids is not None and best_components is not None:
                char_to_ids[char] = best_ids
                char_to_components[char] = best_components
    
    return char_to_ids, char_to_components


def find_composable_characters(available_chars, char_to_ids, char_to_components,
                               target_chars=None):
    """
    查找所有部件都在 available_chars 中的字符。
    
    参数:
        available_chars: set, 当前字体中已有的字符集合
        char_to_ids: dict, 字符 -> IDS 描述
        char_to_components: dict, 字符 -> 部件集合
        target_chars: set or None, 目标字表范围（仅生成此范围内的字符）
                      如果为 None，则不限制范围
    
    返回:
        composable: dict, 可拼成的字符 -> (IDS描述, 部件集合)
    """
    composable = {}
    
    for char, components in char_to_components.items():
        # 跳过已有的字符
        if char in available_chars:
            continue
        
        # 如果 IDS 就是自身，说明是基础部件，跳过
        ids = char_to_ids.get(char, '')
        if ids == char:
            continue
        
        # 字表范围过滤
        if target_chars is not None and char not in target_chars:
            continue
        
        # 检查所有部件是否都在已有字符集合中
        if components.issubset(available_chars):
            composable[char] = (ids, components)
    
    return composable


# ============================================================
# Glyphs.app 集成
# ============================================================

def get_existing_unicode_chars(font):
    """
    获取字体中所有已有字符型的 Unicode 字符集合。
    """
    chars = set()
    for glyph in font.glyphs:
        if glyph.unicode:
            try:
                cp = int(glyph.unicode, 16)
                chars.add(chr(cp))
            except (ValueError, OverflowError):
                pass
    return chars


def glyph_name_to_char(name):
    """
    将 Glyphs 字符形名称转换为 Unicode 字符。
    支持 uniXXXX (BMP) 和 uXXXXX (SMP) 格式。
    """
    name = name.strip()
    if name.startswith('uni') and len(name) == 7:
        # uniXXXX -> 4位hex
        try:
            return chr(int(name[3:], 16))
        except (ValueError, OverflowError):
            return None
    elif name.startswith('u') and len(name) >= 5:
        # uXXXXX -> 5+位hex (SMP)
        try:
            return chr(int(name[1:], 16))
        except (ValueError, OverflowError):
            return None
    return None


def load_charset_file(name):
    chars = set()
    for line in get_embedded_data(name).splitlines():
            name = line.strip()
            if not name:
                continue
            ch = glyph_name_to_char(name)
            if ch:
                chars.add(ch)
    return chars


def create_glyphs_for_composable(font, composable_chars):
    """
    在字体中为可拼成的字符创建新的字符型。
    自动设置全角字符宽度为字体预设尺寸 (font.upm)。
    """
    created_count = 0
    skipped_count = 0
    
    # 探测每个 master 的 UPM（Units Per Em）作为默认全角汉字宽度
    master_widths = {}
    for master in font.masters:
        master_widths[master.id] = font.upm
    
    for char, (ids, components) in sorted(composable_chars.items(), key=lambda x: ord(x[0])):
        unicode_hex = "%04X" % ord(char)
        
        existing = font.glyphs[char]
        if existing is None:
            for g in font.glyphs:
                if g.unicode and g.unicode.upper() == unicode_hex:
                    existing = g
                    break
        
        if existing is not None:
            skipped_count += 1
            continue
        
        new_glyph = GSGlyph(char)
        new_glyph.unicode = unicode_hex
        comp_str = ", ".join(sorted(components))
        new_glyph.note = "IDS: %s | 部件: %s" % (ids, comp_str)
        font.glyphs.append(new_glyph)
        
        # 自动设置新字符的宽度
        for layer in new_glyph.layers:
            if layer.associatedMasterId in master_widths:
                layer.width = master_widths[layer.associatedMasterId]
            else:
                layer.width = font.upm
                
        created_count += 1
    
    return created_count, skipped_count


def run_script_logic(font, choice_idx, charset_list):
    print("=" * 60)
    print("🔤 IDS 汉字拼字脚本")
    print("=" * 60)
    
    target_chars = None  # None = 不限制
    
    if choice_idx > 0 and choice_idx <= len(charset_list):
        chosen_name = charset_list[choice_idx - 1]
        target_chars = load_charset_file(chosen_name)
        print("   ✅ 已选择字表: %s (%d 字)" % (chosen_name, len(target_chars)))
    else:
        print("   ✅ 不限制字表范围")

    # Step 2: 列出已有字符型
    existing_chars = get_existing_unicode_chars(font)
    print("\n📋 步骤 2: 已有字符型统计")
    print("   字体: %s" % font.familyName)
    print("   已有字符型总数: %d" % len(font.glyphs))
    print("   其中有 Unicode 编码的: %d" % len(existing_chars))
    
    if target_chars:
        already_in_font = target_chars & existing_chars
        print("   目标字表中已有字符形: %d / %d" % (len(already_in_font), len(target_chars)))
    
    # 统计 CJK 汉字
    cjk_chars = set()
    for ch in existing_chars:
        cp = ord(ch)
        if (0x4E00 <= cp <= 0x9FFF or       # CJK Unified Ideographs
            0x3400 <= cp <= 0x4DBF or       # CJK Extension A
            0x20000 <= cp <= 0x2A6DF or     # CJK Extension B
            0x2A700 <= cp <= 0x2B73F or     # CJK Extension C
            0x2B740 <= cp <= 0x2B81F or     # CJK Extension D
            0x2B820 <= cp <= 0x2CEAF or     # CJK Extension E
            0x2CEB0 <= cp <= 0x2EBEF or     # CJK Extension F
            0x30000 <= cp <= 0x3134F or     # CJK Extension G
            0x31350 <= cp <= 0x323AF or     # CJK Extension H
            0xF900 <= cp <= 0xFAFF or       # CJK Compatibility Ideographs
            0x2F800 <= cp <= 0x2FA1F):      # CJK Compatibility Supplement
            cjk_chars.add(ch)
    print("   其中 CJK 汉字: %d" % len(cjk_chars))
    
    # Step 3: 加载 IDS 数据库
    print("\n📖 步骤 3: 加载 IDS 数据库...")
    print("   ✅ 加载内嵌 IDS 数据")
    char_to_ids, char_to_components = load_ids_database()
    print("   IDS 数据库中共有 %d 个字符的拆解数据" % len(char_to_components))
    
    # 统计已有字符中可被拆解的数量
    decomposable = 0
    base_components_in_font = set()
    for ch in existing_chars:
        if ch in char_to_components:
            decomposable += 1
            # 如果这个字的 IDS 就是它自己，说明它是基础部件
            if char_to_ids.get(ch, '') == ch:
                base_components_in_font.add(ch)
    
    print("   已有字符中有 IDS 数据的: %d" % decomposable)
    print("   其中作为基础部件的: %d" % len(base_components_in_font))

    
    # Step 4: 查找可拼成的字符
    print("\n🔍 步骤 4: 检索可拼成的新字符...")
    composable = find_composable_characters(
        existing_chars, char_to_ids, char_to_components,
        target_chars=target_chars
    )
    
    if not composable:
        print("   没有找到可以用已有部件拼成的新字符。")
        return
    
    print("   ✅ 找到 %d 个可以拼成的新字符！" % len(composable))
    
    # 显示前 50 个示例
    print("\n   前 50 个示例:")
    for i, (char, (ids, components)) in enumerate(
            sorted(composable.items(), key=lambda x: ord(x[0]))):
        if i >= 50:
            print("   ... 还有 %d 个" % (len(composable) - 50))
            break
        comp_str = "+".join(sorted(components))
        print("   %s (U+%04X) = %s [部件: %s]" % (char, ord(char), ids, comp_str))
    
    # Step 5: 确认并创建字符型
    print("\n🛠  步骤 5: 创建新字符型")
    
    # 使用 Glyphs 的对话框让用户确认
    try:
        from vanilla import dialogs
        result = dialogs.askYesNo(
            messageText="IDS 汉字拼字",
            informativeText="找到 %d 个可以用已有部件拼成的新字符。\n是否创建这些字符型？" % len(composable)
        )
        if result != 1:  # 1 = Yes
            print("   用户取消操作。")
            return
    except ImportError:
        # 如果 vanilla 不可用，直接继续
        pass
    
    created, skipped = create_glyphs_for_composable(font, composable)
    
    print("   ✅ 新创建: %d 个字符型" % created)
    if skipped > 0:
        print("   ⏭  跳过 (已存在): %d 个" % skipped)
    
    print("\n" + "=" * 60)
    print("🎉 完成！")
    print("   新字符型已添加到字体中。")
    print("   每个新字符的 note 中包含了 IDS 拆解信息。")
    print("   请检查字体并按需调整。")
    print("=" * 60)


class IDSComposerDialog:
    def __init__(self, font, charset_list):
        self.font = font
        self.charset_list = charset_list
        
        try:
            import vanilla
        except ImportError:
            print("❌ 错误: 找不到 vanilla 模块，将使用默认选项运行。")
            run_script_logic(self.font, 0, self.charset_list)
            return

        self.w = vanilla.Window((300, 140), "IDS 汉字拼字脚本")
        self.w.text = vanilla.TextBox((15, 15, -15, 22), "选择目标字表:")
        
        choices = ["不限制 (全部)"] + ["%s" % n for n in self.charset_list]
        self.w.popup = vanilla.PopUpButton((15, 40, -15, 20), choices)
        
        # 默认选中第一个字表（如果有）
        if len(choices) > 1:
            self.w.popup.set(1)
            
        self.w.runButton = vanilla.Button((15, 90, -15, 20), "运行", callback=self.runCallback)
        self.w.open()

    def runCallback(self, sender):
        choice_idx = self.w.popup.get()
        self.w.close()
        
        # 清空宏窗口并开始运行
        Glyphs.clearLog()
        Glyphs.showMacroWindow()
        
        run_script_logic(self.font, choice_idx, self.charset_list)


def main():
    font = Glyphs.font
    if font is None:
        try:
            from vanilla import dialogs
            dialogs.message("错误", "没有打开的字体文件。请先打开一个 .glyphs 文件。")
        except:
            print("❌ 错误: 没有打开的字体文件。请先打开一个 .glyphs 文件。")
        return
        
    # 从内嵌数据中提取除 'ids' 以外的所有键作为字表名称
    charset_list = sorted([k for k in EMBEDDED_DATA.keys() if k != "ids"])
    IDSComposerDialog(font, charset_list)

EMBEDDED_DATA = {
    "ids": "",
    "9169": "",
    "big5": "",
    "gb2312": "",
    "通规": "",
}
if __name__ == "__main__":
    main()
